import bisect


class Solution:
    def minimumMountainRemovals(self, nums):
        def lis_ending_lengths(arr):
            tails = []
            lengths = []
            for x in arr:
                idx = bisect.bisect_left(tails, x)
                if idx == len(tails):
                    tails.append(x)
                else:
                    tails[idx] = x
                lengths.append(idx + 1)
            return lengths

        n = len(nums)
        left = lis_ending_lengths(nums)
        right = lis_ending_lengths(nums[::-1])[::-1]
        best = 0
        for i in range(n):
            if left[i] >= 2 and right[i] >= 2:
                best = max(best, left[i] + right[i] - 1)
        return n - best

