class Solution:
    def minimumMountainRemovals(self, nums) -> int:
        n = len(nums)
        left = [1] * n
        for i in range(n):
            for j in range(i):
                if nums[j] < nums[i]:
                    left[i] = max(left[i], left[j] + 1)
        right = [1] * n
        for i in range(n - 1, -1, -1):
            for j in range(i + 1, n):
                if nums[j] < nums[i]:
                    right[i] = max(right[i], right[j] + 1)
        best = 0
        for i in range(n):
            if left[i] >= 2 and right[i] >= 2:
                best = max(best, left[i] + right[i] - 1)
        return n - best

